with open(locals()['var_function-call-14958088041472959322'], 'r') as f:
    sales_data = json.load(f)

with open(locals()['var_function-call-14958088041472958953'], 'r') as f:
    tracks_data = json.load(f)

df_sales = pd.DataFrame(sales_data)
df_sales['total_revenue'] = pd.to_numeric(df_sales['total_revenue'])
df_sales['track_id'] = df_sales['track_id'].astype(str)

df_tracks = pd.DataFrame(tracks_data)
df_tracks['track_id'] = df_tracks['track_id'].astype(str)

def get_revenue(title_keywords, artist_keywords):
    # Title must contain ALL title keywords
    mask_title = pd.Series([True]*len(df_tracks))
    for kw in title_keywords:
        mask_title = mask_title & df_tracks['title'].astype(str).str.contains(kw, case=False, regex=False)
    
    # Artist must contain ANY artist keyword OR be None
    mask_artist = pd.Series([False]*len(df_tracks))
    for kw in artist_keywords:
        mask_artist = mask_artist | df_tracks['artist'].astype(str).str.contains(kw, case=False, regex=False)
    
    mask_artist = mask_artist | df_tracks['artist'].astype(str).str.lower().isin(['none', 'unknown', '', '[unknown]'])
    
    hits = df_tracks[mask_title & mask_artist]
    ids = hits['track_id'].tolist()
    rev = df_sales[df_sales['track_id'].isin(ids)]['total_revenue'].sum()
    return rev, hits[['track_id', 'title', 'artist']].head(5).to_dict(orient='records')

